1	const getNeighbors = (cell: string): string[] => {
2	  const [x, y] = cell.split(",").map(Number);
3	  return [
4	    `${x - 1},${y - 1}`, `${x},${y - 1}`, `${x + 1},${y - 1}`,
5	    `${x - 1},${y}`,                        `${x + 1},${y}`,
6	    `${x - 1},${y + 1}`, `${x},${y + 1}`, `${x + 1},${y + 1}`,
7	  ];
8	};
9	
10	export function nextGeneration(cells: Set<string>): Set<string> {
11	  const result = new Set<string>();
12	  for (const cell of cells) {
13	    const liveNeighborCount = getNeighbors(cell).filter(n => cells.has(n)).length;
14	    if (liveNeighborCount === 2) {
15	      result.add(cell);
16	    }
17	  }
18	  return result;
19	}
